    "startTimeSec": 434.236,
    "startFrame": 13027,
    "durationSec": 3.168,
    "durationFrames": 95,
    "speaker": "めたん",
    "text": "もう完全に部分痩せの概念が崩壊してますわね。\r",
    "speakerColor": "#d6336c",
